// Computes the median of a vector of numeric values using std::nth_element.
// For odd-sized vectors, returns the middle element.
// For even-sized vectors, returns the average of the two middle elements.
// Throws std::invalid_argument if the vector is empty.
template<typename T>
double median(const std::vector<T>& vec) {
    if (vec.empty()) {
        throw std::invalid_argument("Cannot compute median of an empty vector");
    }

    // Create a copy to avoid modifying the original vector
    std::vector<T> data = vec;
    size_t n = data.size();
    size_t mid = n / 2;

    // Partition around the middle element
    std::nth_element(data.begin(), data.begin() + mid, data.end());

    if (n % 2 == 1) {
        // Odd number of elements: return the middle element
        return static_cast<double>(data[mid]);
    } else {
        // Even number of elements: find the max of the lower half and average with upper middle
        // The element at mid is already in place, find the max element before it
        std::nth_element(data.begin(), data.begin() + mid - 1, data.begin() + mid);
        return (static_cast<double>(data[mid - 1]) + static_cast<double>(data[mid])) / 2.0;
    }
}
